echo '
<link href="https://unpkg.com/tabulator-tables@6.3.1/dist/css/tabulator.min.css" rel="stylesheet">
<script type="text/javascript" src="https://unpkg.com/tabulator-tables@6.3.1/dist/js/tabulator.min.js"></script>

<style>
    .tabulator-wrapper {
        width: 100%;
        max-width: 100%;
        overflow: hidden;
    }

    .btn-tabulator-bar {
        margin-bottom: 12px;
        width: 100%;
        display: flex;
        gap: 8px;
        flex-wrap: wrap;
    }

    .btn-tabulator-bar button {
        padding: 8px 14px;
        cursor: pointer;
        border: 1px solid #d0d7de;
        background: linear-gradient(180deg, #ffffff 0%, #f3f6f9 100%);
        color: #1f2937;
        border-radius: 8px;
        font-size: 13px;
        font-weight: 600;
        transition: all .18s ease;
        box-shadow: 0 1px 2px rgba(0,0,0,.05);
    }

    .btn-tabulator-bar button:hover {
        background: linear-gradient(180deg, #f8fafc 0%, #e8eef5 100%);
        border-color: #b8c4d0;
        transform: translateY(-1px);
    }

    #example-table {
        width: 100%;
        max-width: 100%;
        margin-top: 10px;
    }

    #example-table .tabulator {
        width: 100% !important;
        max-width: 100% !important;
        font-size: 12px;
        border: 1px solid #dbe3ea;
        border-radius: 14px;
        overflow: hidden;
        background: #fff;
        box-shadow: 0 8px 24px rgba(15, 23, 42, 0.08);
    }

    #example-table .tabulator-header {
        background: linear-gradient(180deg, #f8fafc 0%, #eef3f8 100%);
        border-bottom: 1px solid #dbe3ea;
    }

    #example-table .tabulator-col {
        background: transparent !important;
        border-right: 1px solid #e7edf3 !important;
    }

    #example-table .tabulator-col:last-child {
        border-right: 0 !important;
    }

    #example-table .tabulator-col-title {
        white-space: normal !important;
        line-height: 1.2;
        font-size: 12px;
        font-weight: 700;
        color: #1f2937;
        padding: 4px 0;
    }

    #example-table .tabulator-header-filter {
        padding: 6px 6px 8px 6px !important;
    }

    .tabulator .tabulator-header .tabulator-col .tabulator-header-filter input,
    .tabulator .tabulator-header .tabulator-col .tabulator-header-filter select {
        width: 100%;
        box-sizing: border-box;
        padding: 7px 9px;
        font-size: 12px;
        border: 1px solid #d5dee8;
        border-radius: 8px;
        background: #fff;
        color: #111827;
        outline: none;
        transition: border-color .18s ease, box-shadow .18s ease;
    }

    .tabulator .tabulator-header .tabulator-col .tabulator-header-filter input:focus,
    .tabulator .tabulator-header .tabulator-col .tabulator-header-filter select:focus {
        border-color: #6ea8fe;
        box-shadow: 0 0 0 3px rgba(59,130,246,.15);
    }

    #example-table .tabulator-row {
        border-bottom: 1px solid #eef2f6;
        transition: background-color .15s ease;
    }

    #example-table .tabulator-row:nth-child(even) {
        background: #fbfdff;
    }

    #example-table .tabulator-row:hover {
        background: #eef6ff !important;
    }

    #example-table .tabulator-row.tabulator-selected {
        background: #dbeafe !important;
    }

    #example-table .tabulator-row .tabulator-cell {
        padding: 7px 8px;
        border-right: 1px solid #f1f5f9;
        color: #1f2937;
        vertical-align: middle;
    }

    #example-table .tabulator-row .tabulator-cell:last-child {
        border-right: 0;
    }

    #example-table .tabulator-frozen {
        background: #f8fbff !important;
    }

    #example-table .tabulator-footer {
        background: #f8fafc;
        border-top: 1px solid #dbe3ea;
        padding: 6px 10px;
    }

    #example-table .tabulator-page {
        border: 1px solid #d5dee8;
        background: #fff;
        color: #374151;
        border-radius: 8px;
        padding: 4px 10px;
        margin: 0 2px;
        transition: all .15s ease;
    }

    #example-table .tabulator-page:hover {
        background: #eef6ff;
        border-color: #b6cdf5;
    }

    #example-table .tabulator-page.active {
        background: #2563eb;
        border-color: #2563eb;
        color: #fff;
    }

    .btn-edit-row {
        padding: 5px 10px;
        border: 1px solid #2563eb;
        background: linear-gradient(180deg, #3b82f6 0%, #2563eb 100%);
        color: #fff;
        border-radius: 8px;
        cursor: pointer;
        font-size: 11px;
        font-weight: 700;
        transition: all .18s ease;
        box-shadow: 0 2px 6px rgba(37,99,235,.22);
    }

    .btn-edit-row:hover {
        background: linear-gradient(180deg, #4f8df3 0%, #1d4ed8 100%);
        transform: translateY(-1px);
    }

    .estado-ok {
        display: inline-block;
        padding: 3px 8px;
        border-radius: 999px;
        font-size: 11px;
        font-weight: 700;
        background: #dcfce7;
        color: #166534;
    }

    .estado-alerta {
        display: inline-block;
        padding: 3px 8px;
        border-radius: 999px;
        font-size: 11px;
        font-weight: 700;
        background: #fef3c7;
        color: #92400e;
    }

    .estado-error {
        display: inline-block;
        padding: 3px 8px;
        border-radius: 999px;
        font-size: 11px;
        font-weight: 700;
        background: #fee2e2;
        color: #991b1b;
    }
</style>

<div class="tabulator-wrapper">
    <div class="btn-tabulator-bar">
        <button id="clear-filters">Limpiar filtros</button>
        <button id="clear-sort">Limpiar orden</button>
    </div>

    <div id="example-table"></div>
</div>';
